section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/ssl-tls-setup.json",
  "type": "object",
  "required": [
    "hostname",
    "tls_min_version",
    "cipher_suites",
    "cert_source",
    "auto_renew",
    "hsts_max_age",
    "ocsp_stapling",
    "post_deploy_scan_grade"
  ],
  "properties": {
    "hostname": {
      "type": "string",
      "description": "string"
    },
    "tls_min_version": {
      "type": "string",
      "description": "enum (TLSv1.2 | TLSv1.3)"
    },
    "cipher_suites": {
      "type": "array",
      "description": "array (only Modern profile)"
    },
    "cert_source": {
      "type": "string",
      "description": "enum (lets_encrypt | internal_ca | imported)"
    },
    "auto_renew": {
      "type": "boolean",
      "description": "boolean (true)"
    },
    "hsts_max_age": {
      "type": "integer",
      "description": "integer (>=31536000)"
    },
    "ocsp_stapling": {
      "type": "boolean",
      "description": "boolean (true)"
    },
    "post_deploy_scan_grade": {
      "type": "string",
      "description": "enum (A+ | A)"
    }
  }
}
